        <div
            class="tta-hover-subpanel"
            data-trigger-class="<?php echo esc_attr( $item['trigger_class'] ); ?>"
            data-parent-class="<?php echo esc_attr( (string) $item['parent_class'] ); ?>"
        >
            <?php
            echo \Elementor\Plugin::$instance
                ->frontend
                ->get_builder_content_for_display( (int) $item['template_id'], true );
            ?>
        </div>
