    <script>
    document.addEventListener('DOMContentLoaded', function () {
        const subpanels = Array.from(document.querySelectorAll('.tta-hover-subpanel[data-trigger-class]'));
        if (!subpanels.length) return;

        const byClass = new Map();
        subpanels.forEach(panel => byClass.set(panel.dataset.triggerClass, panel));

        let hideTimer = null;

        function cancelHide() {
            if (hideTimer) {
                clearTimeout(hideTimer);
                hideTimer = null;
            }
        }

        function getParentPanel(panel) {
            const parentClass = panel.dataset.parentClass;
            if (!parentClass) return null;
            return byClass.get(parentClass) || null;
        }

        function lineageIncludes(candidate, ancestor) {
            let current = candidate;
            while (current) {
                if (current === ancestor) return true;
                current = getParentPanel(current);
            }
            return false;
        }

        function keepAlive(panel) {
            if (panel.matches(':hover')) return true;

            const ownTriggers = document.querySelectorAll('.' + panel.dataset.triggerClass + ':hover');
            if (ownTriggers.length) return true;

            return subpanels.some(other => {
                if (!other.classList.contains('is-active')) return false;
                if (!lineageIncludes(other, panel)) return false;

                if (other.matches(':hover')) return true;
                const triggers = document.querySelectorAll('.' + other.dataset.triggerClass + ':hover');
                return triggers.length > 0;
            });
        }

        function hideBranch(panel) {
            panel.classList.remove('is-active');
            subpanels.forEach(other => {
                if (other !== panel && lineageIncludes(other, panel)) {
                    other.classList.remove('is-active');
                }
            });
        }

        function scheduleHide(panel) {
            cancelHide();
            hideTimer = setTimeout(function () {
                if (!keepAlive(panel)) {
                    hideBranch(panel);
                }
            }, 160);
        }

        function closeUnrelated(targetPanel) {
            subpanels.forEach(other => {
                if (other === targetPanel) return;
                if (lineageIncludes(targetPanel, other)) return; // keep ancestors
                if (lineageIncludes(other, targetPanel)) return; // keep descendants in same branch
                other.classList.remove('is-active');
            });
        }

        function positionSubpanel(panel, trigger) {
            const rect = trigger.getBoundingClientRect();
            const parent = getParentPanel(panel);

            if (parent && parent.classList.contains('is-active')) {
                panel.style.left = (rect.right + window.scrollX + 12) + 'px';
                panel.style.top = (rect.top + window.scrollY) + 'px';
            } else {
                panel.style.left = '0px';
                panel.style.top = (rect.bottom + window.scrollY) + 'px';
            }
        }

        subpanels.forEach(panel => {
            const triggerClass = panel.dataset.triggerClass;
            const triggers = Array.from(document.querySelectorAll('.' + triggerClass));

            triggers.forEach(trigger => {
                trigger.addEventListener('mouseenter', function () {
                    cancelHide();
                    closeUnrelated(panel);
                    positionSubpanel(panel, trigger);
                    panel.classList.add('is-active');
                });

                trigger.addEventListener('mouseleave', function () {
                    scheduleHide(panel);
                });
            });

            panel.addEventListener('mouseenter', cancelHide);
            panel.addEventListener('mouseleave', function () {
                scheduleHide(panel);
            });
        });
    });
    </script>
